insert into public.questions (exam_id, question_text, question_type, options, correct_answer, explanation, marks, order_num) values
('a1b2c3d4-0001-4000-8000-000000000001','What does CPU stand for?','mcq',ARRAY['Central Processing Unit','Central Program Utility','Computer Processing Unit','Core Processing Unit'],0,'CPU stands for Central Processing Unit.',1,1),
('a1b2c3d4-0001-4000-8000-000000000001','Which data structure uses LIFO?','mcq',ARRAY['Queue','Stack','Linked List','Tree'],1,'Stack uses LIFO - last in first out.',1,2),
('a1b2c3d4-0001-4000-8000-000000000001','Time complexity of binary search?','mcq',ARRAY['O(n)','O(n²)','O(log n)','O(1)'],2,'Binary search halves the search space each step.',1,3),
('a1b2c3d4-0001-4000-8000-000000000001','Which OSI layer handles routing?','mcq',ARRAY['Data Link','Transport','Network','Session'],2,'Network layer (Layer 3) handles routing.',1,4),
('a1b2c3d4-0001-4000-8000-000000000001','What is a primary key?','mcq',ARRAY['A key that can be null','Uniquely identifies each row','A foreign key reference','A composite index'],1,'Primary key uniquely identifies each record and cannot be null.',1,5),
('a1b2c3d4-0001-4000-8000-000000000001','Which sort has O(n log n) average case?','mcq',ARRAY['Bubble Sort','Selection Sort','Merge Sort','Insertion Sort'],2,'Merge Sort consistently achieves O(n log n).',1,6),
('a1b2c3d4-0001-4000-8000-000000000001','What does HTML stand for?','mcq',ARRAY['HyperText Markup Language','High Text Machine Language','HyperText Machine Language','HyperTransfer Markup Language'],0,'HTML stands for HyperText Markup Language.',1,7),
('a1b2c3d4-0001-4000-8000-000000000001','What is encapsulation in OOP?','mcq',ARRAY['Inheriting from parent','Hiding internals and exposing only necessary parts','Creating multiple objects','Overriding methods'],1,'Encapsulation bundles data and methods and restricts direct access.',1,8),
('a1b2c3d4-0001-4000-8000-000000000001','Protocol used to send email?','mcq',ARRAY['HTTP','FTP','SMTP','POP3'],2,'SMTP is used to send emails.',1,9),
('a1b2c3d4-0001-4000-8000-000000000001','What is a binary tree?','mcq',ARRAY['A tree with exactly 2 nodes','Each node has at most 2 children','A tree with 2 levels','A sorted tree'],1,'Binary tree: each node has at most 2 children.',1,10),
('a1b2c3d4-0001-4000-8000-000000000001','RAM stands for:','mcq',ARRAY['Read Access Memory','Random Access Memory','Read And Modify','Rapid Access Module'],1,'RAM stands for Random Access Memory.',1,11),
('a1b2c3d4-0001-4000-8000-000000000001','Which is NOT an OOP concept?','mcq',ARRAY['Inheritance','Polymorphism','Compilation','Encapsulation'],2,'Compilation is a process, not an OOP concept.',1,12),
('a1b2c3d4-0001-4000-8000-000000000001','Output of 5 % 2?','mcq',ARRAY['2','2.5','1','0'],2,'5 % 2 = 1. Modulo returns the remainder.',1,13),
('a1b2c3d4-0001-4000-8000-000000000001','Data structure for BFS traversal?','mcq',ARRAY['Stack','Queue','Array','Tree'],1,'BFS uses a Queue (FIFO) to process nodes level by level.',1,14),
('a1b2c3d4-0001-4000-8000-000000000001','SQL stands for?','mcq',ARRAY['Structured Query Language','Simple Query Language','Sequential Query Logic','Standard Query List'],0,'SQL stands for Structured Query Language.',1,15),
('a1b2c3d4-0001-4000-8000-000000000001','IPv4 address has how many bits?','mcq',ARRAY['16','32','64','128'],1,'IPv4 addresses are 32 bits long.',1,16),
('a1b2c3d4-0001-4000-8000-000000000001','Which is a linear data structure?','mcq',ARRAY['Tree','Graph','Array','Heap'],2,'Arrays are linear data structures.',1,17),
('a1b2c3d4-0001-4000-8000-000000000001','What is polymorphism?','mcq',ARRAY['One class inheriting from another','Ability of an object to take many forms','Hiding implementation','Creating objects'],1,'Polymorphism allows different types to be treated uniformly.',1,18),
('a1b2c3d4-0001-4000-8000-000000000001','Which gate outputs 1 only when all inputs are 1?','mcq',ARRAY['OR','NOT','AND','XOR'],2,'AND gate outputs 1 only when ALL inputs are 1.',1,19),
('a1b2c3d4-0001-4000-8000-000000000001','Worst case of Quick Sort?','mcq',ARRAY['O(n log n)','O(n)','O(n²)','O(log n)'],2,'Quick Sort has O(n²) worst case with poor pivot selection.',1,20),
('a1b2c3d4-0001-4000-8000-000000000001','Which memory is non-volatile?','mcq',ARRAY['RAM','Cache','ROM','Register'],2,'ROM is non-volatile - retains data without power.',1,21),
('a1b2c3d4-0001-4000-8000-000000000001','DNS stands for?','mcq',ARRAY['Domain Name System','Data Network Service','Digital Network Security','Domain Node Server'],0,'DNS converts domain names to IP addresses.',1,22),
('a1b2c3d4-0001-4000-8000-000000000001','Which is a high-level language?','mcq',ARRAY['Machine code','Assembly','Python','Binary'],2,'Python is a high-level language.',1,23),
