('a1b2c3d4-0001-4000-8000-000000000001','HTTP method used to send data?','mcq',ARRAY['GET','DELETE','POST','PUT'],2,'POST sends data to the server.',1,26),
('a1b2c3d4-0001-4000-8000-000000000001','What is recursion?','mcq',ARRAY['A loop that runs forever','A function that calls itself','A type of array','A sorting algorithm'],1,'Recursion: a function that calls itself with a base case.',1,27),
('a1b2c3d4-0001-4000-8000-000000000001','Which normal form eliminates partial dependencies?','mcq',ARRAY['1NF','2NF','3NF','BCNF'],1,'2NF eliminates partial dependencies.',1,28),
('a1b2c3d4-0001-4000-8000-000000000001','FIFO stands for?','mcq',ARRAY['First In First Out','Fast Input Fast Output','File In File Out','First Input Final Output'],0,'FIFO: First In First Out - used in queues.',1,29),
('a1b2c3d4-0001-4000-8000-000000000001','OSI layer for end-to-end communication?','mcq',ARRAY['Network','Data Link','Transport','Application'],2,'Transport layer ensures end-to-end communication.',1,30),
('a1b2c3d4-0001-4000-8000-000000000001','A compiler translates:','mcq',ARRAY['Machine to assembly','High-level to machine code','Binary to text','Assembly to high-level'],1,'Compiler translates high-level source code to machine code.',1,31),
('a1b2c3d4-0001-4000-8000-000000000001','Base of hexadecimal?','mcq',ARRAY['2','8','10','16'],3,'Hexadecimal uses base 16.',1,32),
('a1b2c3d4-0001-4000-8000-000000000001','Which data structure uses FIFO?','mcq',ARRAY['Stack','Queue','Tree','Graph'],1,'Queue uses FIFO.',1,33),
('a1b2c3d4-0001-4000-8000-000000000001','What is an algorithm?','mcq',ARRAY['A programming language','A step-by-step procedure to solve a problem','A type of database','A network protocol'],1,'Algorithm: finite steps to solve a problem.',1,34),
('a1b2c3d4-0001-4000-8000-000000000001','Which is NOT a type of software testing?','mcq',ARRAY['Unit Testing','Integration Testing','Compilation Testing','System Testing'],2,'Compilation is not a testing type.',1,35),
('a1b2c3d4-0001-4000-8000-000000000001','TCP/IP stands for?','mcq',ARRAY['Transfer Control Protocol/Internet Protocol','Transmission Control Protocol/Internet Protocol','Transfer Computer Protocol/Internet Program','Transmission Control Program/Internet Protocol'],1,'TCP/IP: Transmission Control Protocol/Internet Protocol.',1,36),
('a1b2c3d4-0001-4000-8000-000000000001','Purpose of a foreign key?','mcq',ARRAY['Uniquely identify a row','Link two tables together','Speed up queries','Store encrypted data'],1,'Foreign key links two tables by referencing another table''s primary key.',1,37),
('a1b2c3d4-0001-4000-8000-000000000001','Which search requires a sorted array?','mcq',ARRAY['Linear Search','Binary Search','DFS','BFS'],1,'Binary search requires a sorted array.',1,38),
('a1b2c3d4-0001-4000-8000-000000000001','WWW stands for?','mcq',ARRAY['World Wide Web','Wide World Web','World Web Wide','Web World Wide'],0,'WWW: World Wide Web.',1,39),
('a1b2c3d4-0001-4000-8000-000000000001','Valid Java access modifier?','mcq',ARRAY['hidden','private','secret','locked'],1,'private is a valid Java access modifier.',1,40),
('a1b2c3d4-0001-4000-8000-000000000001','Array index starts at:','mcq',ARRAY['1','0','-1','2'],1,'Most languages use 0-based array indexing.',1,41),
('a1b2c3d4-0001-4000-8000-000000000001','What is a deadlock?','mcq',ARRAY['A slow process','Two processes waiting for each other indefinitely','A crashed program','An infinite loop'],1,'Deadlock: processes waiting for each other, unable to proceed.',1,42),
('a1b2c3d4-0001-4000-8000-000000000001','Single-line comment symbol in Python?','mcq',ARRAY['//','/*','#','--'],2,'Python uses # for single-line comments.',1,43),
('a1b2c3d4-0001-4000-8000-000000000001','Boolean data type stores?','mcq',ARRAY['Numbers','Text','True or false','Arrays'],2,'Boolean stores only true or false.',1,44),
('a1b2c3d4-0001-4000-8000-000000000001','SQL command to retrieve data?','mcq',ARRAY['GET','FETCH','SELECT','RETRIEVE'],2,'SELECT retrieves data from a database.',1,45),
('a1b2c3d4-0001-4000-8000-000000000001','GUI stands for?','mcq',ARRAY['General User Interface','Graphical User Interface','Global Utility Interface','Generated User Input'],1,'GUI: Graphical User Interface.',1,46),
('a1b2c3d4-0001-4000-8000-000000000001','A computer program is a set of instructions.','true_false',ARRAY['True','False'],0,'True - a program is instructions telling the computer what to do.',1,47),
('a1b2c3d4-0001-4000-8000-000000000001','RAM is non-volatile memory.','true_false',ARRAY['True','False'],1,'False - RAM is volatile. Data is lost when power is off.',1,48),
('a1b2c3d4-0001-4000-8000-000000000001','A stack follows the FIFO principle.','true_false',ARRAY['True','False'],1,'False - Stack follows LIFO. Queue follows FIFO.',1,49),
('a1b2c3d4-0001-4000-8000-000000000001','Python is an interpreted language.','true_false',ARRAY['True','False'],0,'True - Python executes code line by line at runtime.',1,50);
